  1→import { lazy, Suspense } from 'react'
  2→import './App.css'
  3→import { Routes, Route, BrowserRouter, Navigate} from 'react-router-dom'
  4→import { useAuth } from './Context/useAuth.js';
  5→import { LexicalComposer } from '@lexical/react/LexicalComposer';
  6→import { HeadingNode, QuoteNode } from "@lexical/rich-text";
  7→import ImageNode from './components/HomePage/Editor/nodes/ImageNode.jsx';
  8→import Loader from './components/loadingComponent/BgLoader.jsx';
  9→import SeoManager from './seo/SeoManager.jsx';
 10→
 11→const AuthModal = lazy(() => import('./components/AuthModal/AuthModal.jsx'));
 12→const HomePage = lazy(() => import('./components/HomePage/Home.jsx'));
 13→const LoginPage = lazy(() => import('./components/LoginPage/login.jsx'));
 14→const SignUp = lazy(() => import('./components/SignUpPage/signup.jsx'));
 15→const MyProfile = lazy(() => import('./components/ProfilePage/MyProfile.jsx'));
 16→const PostCards = lazy(() => import('./components/HomePage/postCards/PostCards.jsx'));
 17→const ContentView = lazy(() => import('./components/HomePage/ContentViewer/ContentView.jsx'));
 18→const Bookmarks = lazy(() => import('./components/Bookmarks/Bookmarks.jsx'));
 19→const Visitprofile = lazy(() => import('./components/VisitProfile/Visitprofile.jsx'));
 20→const ProfilePostCards = lazy(() => import('./components/HomePage/postCards/ProfilePostCards/ProfilePostCards.jsx'));
 21→const ProfileMediaSection = lazy(() => import('./components/ProfilePage/components/ProfileMediaSection.jsx'));
 22→const VisitedProfilePostCards = lazy(() => import('./components/HomePage/postCards/ProfilePostCards/VisitedProfilePostCards.jsx'));
 23→const VisitedProfileMediaSection = lazy(() => import('./components/VisitProfile/components/VisitedProfileMediaSection.jsx'));
 24→const Notifications = lazy(() => import('./components/Notifications/Notifications.jsx'));
 25→const NotificationCards = lazy(() => import('./components/Notifications/notificationsCards.jsx'));
 26→const UnreadNotification = lazy(() => import('./components/Notifications/UnreadNotificationCard.jsx'));
 27→const Collections = lazy(() => import('./components/collections/Collection.jsx'));
 28→const CollectionJournals = lazy(() => import('./components/collections/CollectionJournalCards.jsx'));
 29→const CollectionViewer = lazy(() => import('./components/collections/CollectionViewer.jsx'));
 30→const ViewUserCollection = lazy(() => import('./components/collections/ViewUserCollections.jsx'));
 31→const OpinionsPage = lazy(() => import('./components/SidebarOpinions/OpinionssPage.jsx'));
 32→const VisitedProfileOpinions = lazy(() => import('./components/SidebarOpinions/visitedProfileOpinions.jsx'));
 33→const MyOpinions = lazy(() => import('./components/SidebarOpinions/MyOpinions.jsx'));
 34→const OpinionViewer = lazy(() => import('./components/SidebarOpinions/opinionViewer.jsx'));
 35→const ExplorePage = lazy(() => import('./components/HomePage/explore/ExplorePage.jsx'));
 36→const GalleryPage = lazy(() => import('./components/HomePage/gallery/GalleryPage.jsx'));
 37→const FreedomWallPage = lazy(() => import('./components/HomePage/freedomWall/FreedomWallPage.jsx'));
 38→const Universe = lazy(() => import('./components/Universe/Universe.jsx'));
 39→const SettingsPage = lazy(() => import('./components/SettingsPage/SettingsPage.jsx'));
 40→const StoryDashboard = lazy(() => import('./components/Stories/StoryDashboard/StoryDashboard.jsx'));
 41→const StoryEditor = lazy(() => import('./components/Stories/StoryEditor/StoryEditor.jsx'));
 42→const StoryChapterManager = lazy(() => import('./components/Stories/StoryChapterManager/StoryChapterManager.jsx'));
 43→const ChapterEditor = lazy(() => import('./components/Stories/ChapterEditor/ChapterEditor.jsx'));
 44→const StoryBrowser = lazy(() => import('./components/Stories/StoryBrowser/StoryBrowser.jsx'));
 45→const StoryLibrary = lazy(() => import('./components/Stories/StoryLibrary/StoryLibrary.jsx'));
 46→const StoryDetail = lazy(() => import('./components/Stories/StoryDetail/StoryDetail.jsx'));
 47→const ChapterReader = lazy(() => import('./components/Stories/ChapterReader/ChapterReader.jsx'));
 48→const ProfileStoriesSection = lazy(() => import('./components/ProfilePage/components/ProfileStoriesSection.jsx'));
 49→const VisitedProfileStoriesSection = lazy(() => import('./components/VisitProfile/components/VisitedProfileStoriesSection.jsx'));
 50→
 51→const AppAuthModal = () => {
 52→  const {showAuthModal, closeAuthModal} = useAuth();
 53→  return <AuthModal isOpen={showAuthModal} onClose={closeAuthModal}/>;
 54→}
 55→
 56→const AppSplash = () => {
 57→  const { loading } = useAuth();
 58→  return <Loader isLoading={loading} />;
 59→}
 60→
 61→const App = () => {
 62→
 63→  const theme = {
 64→    paragraph: 'editor-paragraph',
 65→    heading: {
 66→      h1: 'editor-heading-h1',
 67→      h2: 'editor-heading-h2',
 68→      h3: 'editor-heading-h3',
 69→    },
 70→    quote: 'editor-quote',
 71→    text: {
 72→      bold: 'editor-text-bold',
 73→      italic: 'editor-text-italic',
 74→      underline: 'editor-text-underline',
 75→    }
 76→  }
 77→  
 78→  const initaConfig = {
 79→  namespace: "MyLexicalEditor",
 80→  theme,
 81→  //register nodes
 82→  nodes: [ImageNode, HeadingNode, QuoteNode],
 83→  onError(error){
 84→  throw error;
 85→  },
 86→}
 87→
 88→  return (
 89→    <>
 90→    <LexicalComposer initialConfig={initaConfig}>
 91→      <BrowserRouter>
 92→        <SeoManager />
 93→        <AppSplash />
 94→        <Suspense fallback={null}>
 95→          <AppAuthModal/>
 96→          <Routes>
 97→            <Route path='/' element={<Navigate to='/home' replace/>}/>
 98→            <Route path='/index.html' element={<Navigate to='/home' replace/>}/>
 99→            <Route path='/profile' element={<MyProfile/>}>
100→              <Route index element={<ProfilePostCards/>} />
101→              <Route path='media' element={<ProfileMediaSection/>} />
102→              <Route path='myOpinions' element={<MyOpinions/>}/>
103→              <Route path='stories' element={<ProfileStoriesSection/>}/>
104→            </Route>
105→
106→            <Route path='/visitProfile' element={<Visitprofile/>}>
107→              <Route index element={<VisitedProfilePostCards/>}/>
108→              <Route path='media' element={<VisitedProfileMediaSection/>}/>
109→              <Route path='visitedCollections' element={<CollectionViewer/>}/>
110→              <Route path='visitedOpinions' element={<VisitedProfileOpinions/>}/>
111→              <Route path='stories' element={<VisitedProfileStoriesSection/>}/>
112→            </Route>
113→
114→            <Route path='/u/:username' element={<Visitprofile/>}>
115→              <Route index element={<VisitedProfilePostCards/>}/>
116→              <Route path='media' element={<VisitedProfileMediaSection/>}/>
117→              <Route path='collections' element={<CollectionViewer/>}/>
118→              <Route path='opinions' element={<VisitedProfileOpinions/>}/>
119→              <Route path='stories' element={<VisitedProfileStoriesSection/>}/>
120→            </Route>
121→
122→            <Route path='/home' element={<HomePage/>}>
123→              <Route index element={<PostCards/>}/>
124→              <Route path='following' element={<PostCards/>}/>
125→              <Route path='explore' element={<ExplorePage/>}/>
126→              <Route path='gallery' element={<GalleryPage/>}/>
127→              <Route path='freedom-wall' element={<FreedomWallPage/>}/>
128→              <Route path='contentViewer' element={<ContentView/>}/>
129→              <Route path='post/:journalId' element={<ContentView/>}/>
130→              <Route path='post/:journalId/:slug' element={<ContentView/>}/>
131→              <Route path='bookmark' element={<Bookmarks/>}/>
132→              <Route path='userCollections' element={<ViewUserCollection/>}/>
133→              <Route path='opinions'element={<OpinionsPage/>}/>
134→              <Route path='opinionsViewer' element={<OpinionViewer/>}/>
135→
136→              <Route path='collections' element={<Collections/>}/>
137→              <Route path='collectionCards' element={<CollectionJournals/>}/>
138→              <Route path='settings' element={<SettingsPage/>}/>
139→
140→              {/* Stories routes */}
141→              <Route path='stories' element={<StoryBrowser/>}/>
142→              <Route path='stories/library' element={<StoryLibrary/>}/>
143→              <Route path='stories/dashboard' element={<StoryDashboard/>}/>
144→              <Route path='stories/new' element={<StoryEditor/>}/>
145→              <Route path='stories/:storyId' element={<StoryDetail/>}/>
146→              <Route path='stories/:storyId/edit' element={<StoryEditor/>}/>
147→              <Route path='stories/:storyId/manage' element={<StoryChapterManager/>}/>
148→              <Route path='stories/:storyId/chapter/:chapterId' element={<ChapterReader/>}/>
149→              <Route path='stories/:storyId/chapter/:chapterId/edit' element={<ChapterEditor/>}/>
150→
151→              {/* route for nested notifications */}
152→              <Route path='notifications' element={<Notifications/>}>
153→                <Route index element={<NotificationCards/>}/>
154→                <Route path='unreadNotification' element={<UnreadNotification/>}/>
155→              </Route>  
156→            </Route>   
157→
158→            <Route path='/universe' element={<Universe/>}/>
159→
160→            <Route path='/login' element={<LoginPage/>}/>
161→            <Route path='/signUp' element={<SignUp/>}/>
162→          </Routes>
163→        </Suspense>
164→      </BrowserRouter>
165→    </LexicalComposer>
166→    </>
167→  )
168→}
169→
170→export default App
