  1→/* ── Editor text formats ── */
  2→.editor-text-bold {
  3→    font-weight: bold;
  4→}
  5→.editor-text-italic {
  6→    font-style: italic;
  7→}
  8→.editor-text-underline {
  9→    text-decoration: underline;
 10→}
 11→
 12→/* ── Editor container variables (derived from global theme) ── */
 13→.editor-container {
 14→    --editor-bg: var(--bg-elevated);
 15→    --editor-surface: var(--bg-secondary);
 16→    --editor-text: var(--text-primary);
 17→    --editor-border: var(--border-light);
 18→    --editor-accent: var(--accent-purple);
 19→}
 20→
 21→/* ── Overlay backdrop ── */
 22→.editor-parent-container {
 23→    display: flex;
 24→    justify-content: center;
 25→    align-items: center;
 26→    position: absolute;
 27→    width: 100%;
 28→    height: 100%;
 29→    background-color: var(--bg-overlay);
 30→    backdrop-filter: blur(25px);
 31→    z-index: 130;
 32→}
 33→
 34→/* ── Main editor card ── */
 35→.editor-container {
 36→    display: flex;
 37→    flex-direction: column;
 38→    width: 100%;
 39→    max-width: 720px;
 40→    height: 80%;
 41→    min-height: 0;
 42→    overflow: hidden;
 43→    background-color: var(--editor-bg);
 44→    color: var(--editor-text);
 45→    border-radius: 16px;
 46→    padding: 1rem 1.5rem;
 47→    box-shadow: var(--shadow-modal);
 48→}
 49→
 50→.editor-container.is-canvas-mode{
 51→    max-width: 1100px;
 52→    height: 92%;
 53→    overflow-y: auto;
 54→    overflow-x: hidden;
 55→    overscroll-behavior-y: contain;
 56→    -webkit-overflow-scrolling: touch;
 57→}
 58→
 59→.editor-mode-shell {
 60→    position: relative;
 61→    display: flex;
 62→    flex-direction: column;
 63→    flex: 1;
 64→    min-height: 0;
 65→    overflow: hidden;
 66→}
 67→
 68→.editor-mode-shell.is-canvas-mode {
 69→    overflow-y: auto;
 70→    overflow-x: hidden;
 71→    overscroll-behavior-y: contain;
 72→    -webkit-overflow-scrolling: touch;
 73→}
 74→
 75→/* ── Close button row ── */
 76→.editor-close-bttn-container {
 77→    display: flex;
 78→    width: 100%;
 79→    justify-content: flex-end;
 80→    align-items: center;
 81→}
 82→.editor-close-bttn {
 83→    display: flex;
 84→    align-items: center;
 85→    justify-content: center;
 86→    padding: 0.4rem;
 87→    border: none;
 88→    background: transparent;
 89→    border-radius: 50%;
 90→    cursor: pointer;
 91→    color: var(--text-muted);
 92→    transition: background-color 0.15s ease, color 0.15s ease, transform 0.15s ease;
 93→}
 94→.editor-close-bttn svg {
 95→    fill: var(--text-muted);
 96→    transition: fill 0.15s ease;
 97→}
 98→.editor-close-bttn:hover {
 99→    background-color: var(--bg-pill);
100→    color: var(--editor-text);
101→    transform: scale(1.05);
102→}
103→.editor-close-bttn:hover svg {
104→    fill: var(--editor-text);
105→}
106→
107→/* ── Title input ── */
108→.content-title-input {
109→    margin: 0.5rem 0;
110→    border: none;
111→    border-bottom: 2px solid transparent;
112→    background-color: transparent;
113→    font-size: 1.75rem;
114→    font-weight: 650;
115→    font-family: var(--font-serif);
116→    padding: 0.5rem 0.25rem;
117→    color: var(--editor-text);
118→    transition: border-color 0.25s ease;
119→}
120→.content-title-input::placeholder {
121→    color: var(--text-muted);
122→}
123→.content-title-input:focus {
124→    outline: none;
125→    border-bottom-color: var(--editor-accent);
126→}
127→
128→/* ── Toolbar (above content) ── */
129→.toolbar-wrapper {
130→    display: flex;
131→    align-items: center;
132→    border-top: 1px solid var(--editor-border);
133→    border-bottom: 1px solid var(--editor-border);
134→    padding: 0.35rem 0;
135→    margin-bottom: 0;
136→    position: sticky;
137→    top: 0;
138→    z-index: 5;
139→    background-color: var(--editor-bg);
140→}
141→.toolbar {
142→    display: flex;
143→    align-items: center;
144→    gap: 2px;
145→    width: 100%;
146→    flex-wrap: wrap;
147→}
148→.group {
149→    display: flex;
150→    align-items: center;
151→    gap: 2px;
152→}
153→.toolbar-divider {
154→    width: 1px;
155→    height: 20px;
156→    background-color: var(--editor-border);
157→    margin: 0 6px;
158→    flex-shrink: 0;
159→}
160→.toolbar-bttns {
161→    display: flex;
162→    width: fit-content;
163→    height: fit-content;
164→    justify-content: center;
165→    align-items: center;
166→    padding: 0.4rem;
167→    border-radius: 6px;
168→    cursor: pointer;
169→    transition: all 0.15s ease;
170→    user-select: none;
171→    color: var(--editor-text);
172→}
173→.toolbar-bttns svg {
174→    fill: var(--editor-text);
175→    transition: fill 0.15s ease;
176→}
177→.toolbar-bttns:hover {
178→    background-color: var(--bg-pill);
179→}
180→.is-active {
181→    display: flex;
182→    justify-content: center;
183→    align-items: center;
184→    width: fit-content;
185→    height: fit-content;
186→    padding: 0.4rem;
187→    border-radius: 6px;
188→    cursor: pointer;
189→    transition: all 0.15s ease;
190→    user-select: none;
191→    background-color: color-mix(in srgb, var(--editor-accent) 15%, transparent);
192→}
193→.is-active svg {
194→    fill: var(--editor-accent);
195→}
196→
197→/* ── Color pickers ── */
198→.toolbar-color-picker {
199→    position: relative;
200→    display: flex;
201→    align-items: center;
202→}
203→.toolbar-color-trigger {
204→    display: inline-flex;
205→    align-items: center;
206→    gap: 6px;
207→    padding: 0.35rem 0.45rem;
208→    border-radius: 6px;
209→    border: none;
210→    background: transparent;
211→    cursor: pointer;
212→    color: var(--editor-text);
213→    transition: background-color 0.15s ease;
214→}
215→.toolbar-color-trigger:hover {
216→    background-color: var(--bg-pill);
217→}
218→.toolbar-color-icon {
219→    font-weight: 700;
220→    font-size: 0.9rem;
221→    line-height: 1;
222→}
223→.toolbar-color-swatch {
224→    width: 16px;
225→    height: 4px;
226→    border-radius: 3px;
227→    border: 1px solid var(--editor-border);
228→}
229→.color-popover {
230→    position: absolute;
231→    top: calc(100% + 6px);
232→    left: 0;
233→    display: grid;
234→    grid-template-columns: repeat(6, 18px);
235→    gap: 6px;
236→    padding: 8px;
